"use client";

import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  pureCashHero,
  cashCarve,
  cashKpis,
  providers,
  cashObligations,
  cashAI,
} from "@/features/finance/api/finance-cash-data";
import "./cash.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const fmtK = (v: number) =>
  Math.abs(v) >= 1000 ? `$${Math.round(v / 1000)}K` : `$${Math.round(v)}`;

export default function CashPage() {
  const total = cashCarve.reduce((a, c) => a + c.value, 0);
  const pctOf = (v: number) => (v / total) * 100;
  const pureSlice = cashCarve.find((c) => c.key === "pure");
  const cutLeftPct = pureSlice ? 100 - pctOf(pureSlice.value) : 50;
  const weekNet = cashObligations.reduce((a, o) => a + o.amount, 0);

  return (
    <div className="finance-cash-page">
      <DeptHeader
        dept="finance"
        title="Cash & Payments"
        meta={
          <>
            <span className="live">Live</span> · What&rsquo;s truly safe to spend · bank + payment providers
          </>
        }
        actions={
          <>
            <button className="btn-util">Review transactions →</button>
            <BridgePrimaryButton dept="finance">Approve payments →</BridgePrimaryButton>
          </>
        }
      />
      <div className="head-pad" />

      {/* AI strip */}
      <AIStrip label={cashAI.label} meta={cashAI.meta} cards={cashAI.cards} />

      {/* ───── Pure Cash hero ───── */}
      <SectionLabel>Pure Cash — what&rsquo;s genuinely yours to deploy today</SectionLabel>
      <div className="purecash">
        <div className="pc-head">
          <div className="pc-headline">
            <div className="rbig">{fmtUSD(pureCashHero.pureCash)}</div>
            <div className="rlbl">
              Pure Cash
              <br />
              safe to deploy
              <span className="delta">
                ↑ {fmtK(pureCashHero.deltaVsLastMonth)} vs last month
              </span>
            </div>
          </div>
          <div className="pc-of">
            <div className="k">of {fmtUSD(pureCashHero.accessible)} accessible</div>
            <div className="v">
              {((pureCashHero.pureCash / pureCashHero.accessible) * 100).toFixed(1)}% is yours
            </div>
          </div>
        </div>

        <div className="pc-carve">
          {cashCarve.map((s) => {
            const w = pctOf(s.value);
            return (
              <div
                key={s.key}
                className={`pc-seg ${s.key}`}
                style={{ width: `${w.toFixed(1)}%` }}
              >
                <span className="sv">
                  {s.key === "pure"
                    ? `${fmtUSD(s.value)} yours`
                    : `−${fmtK(s.value)}`}
                </span>
                <span className="sk">
                  {s.key === "pure" ? "safe to deploy" : s.label}
                </span>
              </div>
            );
          })}
          <div className="cut" style={{ left: `${cutLeftPct.toFixed(1)}%` }} />
        </div>

        <div className="pc-legend">
          <span className="li tax"><i /><b>Sales tax</b> · owed next filing</span>
          <span className="li holds"><i /><b>Gateway holds</b> · pending settlement</span>
          <span className="li reserve"><i /><b>Tax reserve</b> · protected for Q-end</span>
          <span className="li pure"><i /><b>Pure Cash</b> · safe to deploy</span>
        </div>

        <div className="pc-line">
          Half of what your balance shows is already spoken-for. The <b>$476K to the left of the line</b> is the money most founders accidentally spend — then can&rsquo;t cover at tax time.
          <span className="q" title="Pure Cash = total accessible − sales tax owed − gateway holds pending settlement − tax reserve.">?</span>
        </div>
      </div>

      {/* ───── KPI strip ───── */}
      <div className="cash-kpis">
        {cashKpis.map((k, i) => (
          <div key={i} className="cash-kpi">
            <div className="l">{k.label}</div>
            <div className={`v ${k.color || ""}`}>
              {k.value}
              {k.unit && (
                <span style={{ fontSize: 15, color: "var(--ink-3)" }}> {k.unit}</span>
              )}
            </div>
            <div className="s">{k.sub}</div>
          </div>
        ))}
      </div>

      {/* ───── Providers ───── */}
      <SectionLabel>By provider — what&rsquo;s held vs available</SectionLabel>
      <div className="providers">
        {providers.map((p) => (
          <div key={p.name} className="prov">
            <div className="prov-head">
              <div className="prov-logo" style={{ background: p.brandColor }}>
                {p.name === "Stripe" ? "S" : "P"}
              </div>
              <div>
                <div className="prov-name">{p.name}</div>
                <div className="prov-status">
                  <span className="d" />
                  Connected · live sync
                </div>
              </div>
            </div>
            <div className="prov-bal">
              <div className="cell">
                <div className="k held">Held</div>
                <div className="v">{fmtUSD(p.held)}</div>
              </div>
              <div className="cell">
                <div className="k avail">Available</div>
                <div className="v">{fmtUSD(p.available)}</div>
              </div>
            </div>
            <div className="prov-rel">
              <div className="prov-rel-label">Upcoming releases</div>
              {p.releases.map((r, i) => (
                <div key={i} className="rel-row">
                  <span className="when">
                    <span className="day">{r.when}</span>
                    {r.desc}
                  </span>
                  <span className="plus">+{fmtUSD(r.amount)}</span>
                </div>
              ))}
            </div>
            <div className="prov-fee">
              <span className="feewrap">
                <span className="fk">
                  <b>Effective fee</b> this month
                </span>
                <span className="fv">
                  <span className="rate">{p.effectiveFeeRate}</span> · {fmtUSD(p.effectiveFeeAmount)}
                </span>
              </span>
              <button className="btn-withdraw">Withdraw to bank →</button>
            </div>
          </div>
        ))}
      </div>

      {/* ───── Obligations preview ───── */}
      <SectionLabel>This week&rsquo;s payments — full timeline on Cash Flow</SectionLabel>
      <div className="oblig">
        {cashObligations.map((o, i) => (
          <div key={i} className="oblig-row">
            <span className="date">{o.date}</span>
            <span className="desc">
              {o.desc}
              <span className="tag">{o.tag}</span>
            </span>
            <span className={`amt ${o.amount > 0 ? "in" : "out"}`}>
              {o.amount > 0 ? "+" : "−"}{fmtUSD(Math.abs(o.amount))}
            </span>
          </div>
        ))}
        <div className="oblig-foot">
          <span className="k">Net this week</span>
          <span>
            <span className="v">
              {weekNet > 0 ? "+" : "−"}{fmtUSD(Math.abs(weekNet))}
            </span>
            <a className="oblig-link" href="/finance/cashflow">Open Cash Flow →</a>
          </span>
        </div>
      </div>
    </div>
  );
}
