export interface CashCarveSlice {
  /** Internal key for theming */
  key: "tax" | "holds" | "reserve" | "pure";
  label: string;
  /** USD */
  value: number;
  /** Where in the legend the dot appears (for the labelled `i` icon) */
  legendNote: string;
}

export interface ProviderRelease {
  when: string; // "Tomorrow", "In 2 days"
  desc: string; // "rolling payout"
  amount: number;
}

export interface Provider {
  name: string;
  brandColor: string;
  held: number;
  available: number;
  releases: ProviderRelease[];
  effectiveFeeRate: string;
  effectiveFeeAmount: number;
}

export interface ObligationRow {
  date: string;
  desc: string;
  tag: "inflow" | "supplier" | "recurring" | "tax";
  amount: number; // positive = inflow, negative = outflow
}

